import { useScrollReveal } from '../hooks/useScrollReveal';
import './Skills.css';

const SKILLS = [
  { category: '', items: ['React', 'TypeScript', 'Next.js', 'HTML/CSS', 'TailwindCSS'] },
  { category: 'Backend',  items: ['Node.js', 'Python', 'FastAPI', 'PostgreSQL', 'Redis'] },
  { category: 'Fintech',  items: ['Paystack', 'Flutterwave', 'KYC Flows', 'Escrow Architecture', 'Fraud Signals'] },
  { category: 'Video',    items: ['Premiere Pro', 'After Effects', 'DaVinci Resolve', 'Colour Grading', 'Motion Graphics'] },
  { category: 'Tools',    items: ['Git', 'Docker', 'Figma', 'Supabase', 'Firebase'] },
];

export default function Skills() {
  const ref = useScrollReveal();

  return (
    <section className="skills section" id="skills">
      <div className="section__inner">
        <div className="section__label">Toolkit</div>
        <h2 className="section__heading" ref={ref}>
          Skills &amp; <span className="gradient-text">technologies</span>
        </h2>

        { <div className="skills__grid">
          {SKILLS.map((group, i) => {
            // const cardRef = useScrollReveal();
            return (
              <div
                key={group.category}
                className="skills__card"
                // ref={cardRef}
                style={{ transitionDelay: `${i * 0.07}s` }}
              >
                <p className="skills__category">{group.category}</p>
                <div className="skills__items">
                  {group.items.map(s => (
                    <span key={s} className="skills__chip">{s}</span>
                  ))}
                </div>
              </div>
            );
          })}
        </div> }
        <div className="skills_grid">
        {SKILLS.map((group, i) => (
          <SkillCard key={group.category} group={group} index={i} />
        ))}
      </div>
      </div>
    </section>
  );
}

function SkillCard({ group, index }) {
  const cardRef = useScrollReveal(); // Called at the top level of its own component!

  return (
    <div
      className="skills_card"
      ref={cardRef}
      style={{ transitionDelay: `${index * 0.07}s` }}
    >
      <p className="skills_category">{group.category}</p>
      <div className="skills_items">
         {/* Put whatever loop or items go inside here */}
      </div>
    </div>
  );
}
